#include <algorithm>

using namespace std;

long long solve(vector<long long> landStartTime, vector<long long> landDuration, vector<long long> waterStartTime, vector<long long> waterDuration) {
    long long min_time = 1e18;
    int n = landStartTime.size();
    int m = waterStartTime.size();
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            // Land first
            long long land_start = landStartTime[i];
            long long land_end = land_start + landDuration[i];
            long long water_start = max(waterStartTime[j], land_end);
            long long water_end = water_start + waterDuration[j];
            long long land_first = water_end;

            // Water first
            long long water_start2 = waterStartTime[j];
            long long water_end2 = water_start2 + waterDuration[j];
            long long land_start2 = max(landStartTime[i], water_end2);
            long long land_end2 = land_start2 + landDuration[i];
            long long water_first = land_end2;

            long long current_min = min(land_first, water_first);
            if (current_min < min_time) {
                min_time = current_min;
            }
        }
    }
    return min_time;
}

