public static long solve(long[] landStartTime, long[] landDuration, long[] waterStartTime, long[] waterDuration) {
    long min_time = Long.MAX_VALUE;
    int n = landStartTime.length;
    int m = waterStartTime.length;
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            // Land first
            long landStart = landStartTime[i];
            long landEnd = landStart + landDuration[i];
            long waterStart = Math.max(waterStartTime[j], landEnd);
            long waterEnd = waterStart + waterDuration[j];
            long landFirst = waterEnd;

            // Water first
            long waterStart2 = waterStartTime[j];
            long waterEnd2 = waterStart2 + waterDuration[j];
            long landStart2 = Math.max(landStartTime[i], waterEnd2);
            long landEnd2 = landStart2 + landDuration[i];
            long waterFirst = landEnd2;

            long currentMin = Math.min(landFirst, waterFirst);
            if (currentMin < min_time) {
                min_time = currentMin;
            }
        }
    }
